import { NextResponse } from 'next/server';
import { GoogleGenerativeAI } from '@google/generative-ai';

const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY || '');

export async function POST(req: Request) {
  try {
    const { image } = await req.json();

    if (!image) {
      return NextResponse.json(
        { error: '이미지가 제공되지 않았습니다' },
        { status: 400 }
      );
    }

    if (!process.env.GEMINI_API_KEY) {
      return NextResponse.json(
        { error: 'Gemini API 키가 설정되지 않았습니다. .env.local 파일에 GEMINI_API_KEY를 추가하세요.' },
        { status: 500 }
      );
    }

    const base64Data = image.replace(/^data:image\/(png|jpeg|webp|jpg|gif);base64,/, '');

    const model = genAI.getGenerativeModel({
      model: 'gemini-2.0-flash',
      generationConfig: {
        responseMimeType: 'application/json',
      },
    });

    const prompt = `
You are a world-class AI Prompt Engineer specializing in generative image platforms.
Analyze the provided image and generate tailored prompts for 4 platforms, following each platform's OFFICIAL guide rules precisely.

═══ STEP 1: VISUAL ANALYSIS ═══
First, identify: Subject, Medium/Style, Environment, Lighting, Color Palette, Composition, Camera Angle, Mood.

═══ STEP 2: PLATFORM-SPECIFIC PROMPT GENERATION ═══

──── MIDJOURNEY (키워드 압축형) ────
Rules from official guide:
- Structure: Subject + Medium + Environment + Lighting/Color/Mood + Composition + Parameters
- Use SHORT, COMPRESSED KEYWORDS — not sentences. This is about "picking good visual keywords", not "writing well".
- Use SPECIFIC words: "gigantic" not "big", "three cats" not "cats"
- Focus on WHAT TO INCLUDE, never describe what to exclude
- Shorter prompts = more diversity but less control
- Add parameters at the end: --v 6.1 --style raw --ar X:Y --s NNN

SCORING the generated Midjourney prompt (0-100) using 6 axes:
1. Subject Specificity (×3): vague=0-3, moderate=4-7, highly specific=8-10
2. Medium/Style (×2): unspecified=0-3, basic=4-7, precise=8-10
3. Environment (×2): unspecified=0-3, basic=4-7, vivid=8-10
4. Lighting/Color/Mood (×1.5): unspecified=0-3, basic=4-7, cinematic=8-10
5. Composition/Camera (×1): unspecified=0-3, basic=4-7, professional=8-10
6. Parameter Usage (×0.5): none=0, basic=4-7, advanced combo=8-10
Penalties: sentence-style(-5), negatives(-3), vague adjectives like "beautiful"(-2), >50 words(-3)
Formula: sum(axis × weight) / max_possible × 100 - penalties

──── NANOBANANA 생성모드 (7단계 구조화형) ────
Rules from official guide:
- Think of prompts as "structured briefings"
- THE EARLIER details appear, THE MORE WEIGHT they carry
- Follow this EXACT 7-step order:
  1. Subject: who/what, quantity, features (MOST IMPORTANT — must come first)
  2. Action/Relation: what they're doing, relationship to other elements
  3. Background: place, time, weather, indoor/outdoor
  4. Style/Medium: photo, illustration, 3D, watercolor, realism level
  5. Composition/Camera: close-up, wide shot, angle, lens, depth of field
  6. Lighting/Color: backlighting, neon, warm/cool tones
  7. Key Details/Constraints: sharpness, texture, "no text", "no watermark"

SCORING the generated Nanobanana prompt (0-100):
- Each of the 7 steps: present=weighted score, absent=0
  Step weights: ①×3, ②×2, ③×2, ④×2, ⑤×1.5, ⑥×1.5, ⑦×1
- ORDER BONUS: All 7 steps in correct order = +5 bonus
- ORDER PENALTY: Each out-of-order step = -2
Formula: sum(step_present × weight × quality) / max × 100 + order_bonus

──── HIGSFIELD (영상 생성) ────
- Focus on camera movement (Pan, Zoom, Tilt, Orbital Arc) and motion strength
- Declare Action, Motion Strength, Camera Movement, and Vibe clearly
- Include "Soul ID" hashtag at end for character consistency

──── WEAVY (노드 그래프 에디터) ────
- Extract computational "nodes" to recreate/manipulate the image
- Return array of nodes (e.g., ["Canny Edge", "Depth Map", "Softbox Light"])
- Provide instruction reasoning for node selection
- Provide stringified JSON graph (nodes with id, type, params + links with from/to)

═══ STEP 3: RETURN FORMAT ═══
Return ONLY a valid JSON object matching this schema:
{
  "midjourney": {
    "english": "string (final keyword-compressed prompt)",
    "korean": "string (한국어 의미 해석)",
    "reasoning": "string (이 프롬프트를 이렇게 설계한 이유, 한국어로)",
    "score": number (0-100),
    "breakdown": [
      {"axis": "피사체 구체성", "score": number, "weight": 3, "note": "string"},
      {"axis": "매체/스타일", "score": number, "weight": 2, "note": "string"},
      {"axis": "환경/배경", "score": number, "weight": 2, "note": "string"},
      {"axis": "조명/색감/분위기", "score": number, "weight": 1.5, "note": "string"},
      {"axis": "구도/카메라", "score": number, "weight": 1, "note": "string"},
      {"axis": "파라미터 활용", "score": number, "weight": 0.5, "note": "string"}
    ],
    "penalties": [{"reason": "string", "points": number}]
  },
  "nanobanana": {
    "english": "string (final 7-step structured prompt)",
    "korean": "string (한국어 의미 해석)",
    "reasoning": "string (7단계 구조를 어떻게 적용했는지, 한국어로)",
    "score": number (0-100),
    "breakdown": [
      {"step": "① 피사체", "score": number, "weight": 3, "note": "string"},
      {"step": "② 동작/관계", "score": number, "weight": 2, "note": "string"},
      {"step": "③ 배경", "score": number, "weight": 2, "note": "string"},
      {"step": "④ 스타일/매체", "score": number, "weight": 2, "note": "string"},
      {"step": "⑤ 구도/카메라", "score": number, "weight": 1.5, "note": "string"},
      {"step": "⑥ 조명/색상", "score": number, "weight": 1.5, "note": "string"},
      {"step": "⑦ 핵심 디테일", "score": number, "weight": 1, "note": "string"}
    ],
    "orderBonus": number
  },
  "higsfield": {
    "english": "string",
    "korean": "string",
    "reasoning": "string (한국어로)"
  },
  "weavy": {
    "nodes": ["string"],
    "instruction": "string (한국어로)",
    "json": "string (stringified JSON node graph)"
  }
}
`;

    const result = await model.generateContent([
      prompt,
      {
        inlineData: {
          data: base64Data,
          mimeType: 'image/jpeg',
        },
      },
    ]);

    const responseText = result.response.text();

    return new NextResponse(responseText, {
      status: 200,
      headers: {
        'Content-Type': 'application/json',
      },
    });

  } catch (error: any) {
    console.error('Error analyzing image:', error);
    return NextResponse.json(
      { error: error?.message || '이미지 분석에 실패했습니다' },
      { status: 500 }
    );
  }
}

import { NextResponse } from 'next/server';
import { GoogleGenerativeAI, Content } from '@google/generative-ai';

const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY || '');

const MIDJOURNEY_SYSTEM = `
당신은 미드저니 프롬프트 전문 코치입니다.

═══ 미드저니 프롬프트 공식 가이드 규칙 ═══
1. 구조: 주제 + 매체 + 환경 + 조명/색감/분위기 + 구도 + 파라미터
2. 짧고 압축된 키워드 중심 — 문장형이 아니라 "좋은 시각 키워드 고르기"
3. 모호한 형용사(beautiful, nice) 대신 구체적 단어(gigantic, iridescent)
4. "cats" 대신 "three cats" — 수량 명시
5. 원하지 않는 것을 설명하지 말고, 원하는 장면을 중심으로
6. 파라미터: --v 6.1 --style raw --ar 16:9 --s 250 등

═══ 채점 루브릭 (6축, 총 100점) ═══
각 축은 0~10점이며 가중치를 곱하여 합산합니다:
1. 피사체 구체성 (×3): 모호=0-3, 보통=4-7, 고도 구체화=8-10
2. 매체/스타일 (×2): 미지정=0-3, 기본=4-7, 정밀=8-10
3. 환경/배경 (×2): 미지정=0-3, 기본=4-7, 생생함=8-10
4. 조명/색감/분위기 (×1.5): 미지정=0-3, 기본=4-7, 시네마틱=8-10
5. 구도/카메라 (×1): 미지정=0-3, 기본=4-7, 전문적=8-10
6. 파라미터 활용 (×0.5): 없음=0, 기본=4-7, 고급 조합=8-10
감점: 문장형(-5), 부정어(-3), 모호한 형용사(-2), 50단어 초과(-3)
공식: Σ(축×가중치) / 최대점수 × 100 - 감점

═══ 역할 ═══
1. 사용자의 프롬프트를 위 루브릭으로 정확히 채점하세요.
2. 구체적인 개선 제안을 한국어로 제공하세요.
3. 사용자가 수정을 요청하면, 개선된 프롬프트를 생성하고 다시 채점하세요.

═══ 응답 형식 (반드시 JSON) ═══
{
  "score": number,
  "badges": {
    "specificity": "string (피사체 구체성 평가)",
    "medium": "string (매체/스타일 평가)",
    "environment": "string (환경 평가)",
    "lighting": "string (조명/색감 평가)",
    "composition": "string (구도 평가)",
    "parameters": "string (파라미터 평가)"
  },
  "reasoning": "string (한국어 진단 설명)",
  "revisedPrompt": "string (개선된 영어 프롬프트)",
  "suggestions": ["string (개선 제안 1)", "string (개선 제안 2)"]
}
`;

const NANOBANANA_GEN_SYSTEM = `
당신은 나노바나나 프롬프트 전문 코치입니다.

═══ 나노바나나 생성 프롬프트 공식 가이드 규칙 ═══
프롬프트를 "구조화된 지시서"로 생각하세요. 가장 중요한 요소를 앞에 두세요.

7단계 순서:
① 피사체: 누구/무엇인지, 수량과 특징 (가장 먼저, 가장 중요!)
② 동작과 관계: 무엇을 하고 있는지, 다른 요소와의 관계
③ 배경: 장소, 시간, 날씨, 실내외
④ 스타일과 매체: 사진, 일러스트, 3D, 수채화, 사실성 수준
⑤ 구도와 카메라: 클로즈업, 와이드샷, 앵글, 렌즈, 피사계 심도
⑥ 조명과 색상: 역광, 네온, 따뜻한 색, 차가운 색
⑦ 핵심 디테일과 제약: 선명도, 질감, "텍스트 없음" 등

═══ 채점 루브릭 (7단계, 총 100점) ═══
각 단계 0~10점 × 가중치:
① 피사체(×3), ② 동작(×2), ③ 배경(×2), ④ 스타일(×2), ⑤ 구도(×1.5), ⑥ 조명(×1.5), ⑦ 디테일(×1)
순서 보너스: 7단계가 올바른 순서대로 배치 = +5점
순서 감점: 순서 뒤바뀐 단계마다 -2점
공식: Σ(단계 존재 × 가중치 × 품질) / 최대 × 100 + 순서보너스

═══ 응답 형식 (반드시 JSON) ═══
{
  "score": number,
  "badges": {
    "subject": "string (피사체 평가)",
    "action": "string (동작/관계 평가)",
    "background": "string (배경 평가)",
    "style": "string (스타일 평가)",
    "composition": "string (구도 평가)",
    "lighting": "string (조명 평가)",
    "details": "string (디테일 평가)"
  },
  "reasoning": "string (한국어 진단 설명)",
  "revisedPrompt": "string (개선된 영어 프롬프트)",
  "suggestions": ["string"]
}
`;

const NANOBANANA_EDIT_SYSTEM = `
당신은 나노바나나 편집 프롬프트 전문 코치입니다.

═══ 나노바나나 편집 프롬프트 공식 가이드 규칙 ═══
편집 프롬프트는 "유지 + 변경 + 방법 + 제약" 구조를 사용합니다.
먼저 무엇을 건드리지 말아야 하는지 적고, 그다음 무엇을 어떻게 바꿀지 명확히 적습니다.

4단계 구조:
① 유지 요소 (×3): 바꾸지 않을 요소를 명확히 명시 (얼굴, 포즈, 의상 등)
② 변경 요소 (×3): 무엇을 바꿀지 구체적으로 선언
③ 방법/스타일 (×2): 변경 후 원하는 톤, 스타일, 강도
④ 제약 조건 (×2): 절대 변하면 안 되는 추가 사항

핵심 원칙:
- 한 번에 한두 가지만 바꾸세요
- "더 예쁘게" 같은 추상 표현 대신 조명·렌즈·질감·스타일을 구체적으로
- 유지 조건을 먼저 쓰세요 (특히 얼굴, 포즈, 나이, 피부톤)
- 모순된 조건을 피하세요

═══ 채점 루브릭 (4단계, 총 100점) ═══
① 유지 명확도(×3), ② 변경 구체성(×3), ③ 스타일 적합도(×2), ④ 제약 명시도(×2)
공식: Σ(단계 × 가중치 × 품질) / 최대 × 100

═══ 응답 형식 (반드시 JSON) ═══
{
  "score": number,
  "badges": {
    "keepClarity": "string (유지 요소 명확도)",
    "changeSpecificity": "string (변경 요소 구체성)",
    "styleMatch": "string (스타일 적합도)",
    "constraints": "string (제약 명시도)"
  },
  "reasoning": "string (한국어 진단 설명)",
  "revisedPrompt": "string (개선된 영어 프롬프트)",
  "suggestions": ["string"]
}
`;

type Platform = 'midjourney' | 'nanobanana';
type Mode = 'generation' | 'editing';

function getSystemPrompt(platform: Platform, mode: Mode): string {
  if (platform === 'midjourney') return MIDJOURNEY_SYSTEM;
  if (platform === 'nanobanana' && mode === 'editing') return NANOBANANA_EDIT_SYSTEM;
  return NANOBANANA_GEN_SYSTEM;
}

export async function POST(req: Request) {
  try {
    const { prompt, platform, mode, history } = await req.json();

    if (!prompt) {
      return NextResponse.json(
        { error: '프롬프트를 입력해 주세요' },
        { status: 400 }
      );
    }

    if (!process.env.GEMINI_API_KEY) {
      return NextResponse.json(
        { error: 'Gemini API 키가 설정되지 않았습니다' },
        { status: 500 }
      );
    }

    const selectedPlatform: Platform = platform || 'midjourney';
    const selectedMode: Mode = mode || 'generation';
    const systemPrompt = getSystemPrompt(selectedPlatform, selectedMode);

    const model = genAI.getGenerativeModel({
      model: 'gemini-2.0-flash',
      systemInstruction: systemPrompt,
      generationConfig: {
        responseMimeType: 'application/json',
      },
    });

    // Build conversation history for multi-turn
    const contents: Content[] = [];

    if (history && Array.isArray(history)) {
      for (const msg of history) {
        if (msg.role === 'user') {
          contents.push({ role: 'user', parts: [{ text: msg.content }] });
        } else if (msg.role === 'ai') {
          contents.push({ role: 'model', parts: [{ text: msg.content }] });
        }
      }
    }

    // Add current user message
    contents.push({ role: 'user', parts: [{ text: prompt }] });

    const chat = model.startChat({ history: contents.slice(0, -1) });
    const result = await chat.sendMessage(prompt);
    const responseText = result.response.text();

    return new NextResponse(responseText, {
      status: 200,
      headers: { 'Content-Type': 'application/json' },
    });

  } catch (error: any) {
    console.error('Score API error:', error);
    return NextResponse.json(
      { error: error?.message || '채점에 실패했습니다' },
      { status: 500 }
    );
  }
}

"use client";

import { useState, useRef } from "react";
import { KnowledgeItem } from "@/data/schema";
import { useToast } from "./Toast";

export default function HoverVideoCard({ item }: { item: KnowledgeItem }) {
  const [isHovered, setIsHovered] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const { toast } = useToast();

  const handleMouseEnter = () => {
    setIsHovered(true);
    if (videoRef.current) {
      videoRef.current.play().catch(() => {});
    }
  };

  const handleMouseLeave = () => {
    setIsHovered(false);
    if (videoRef.current) {
      videoRef.current.pause();
      videoRef.current.currentTime = 0;
    }
  };

  const isVideoProvider = item.platforms.includes("higsfield");
  const videoSrc = item.videoUrl || "https://www.w3schools.com/html/mov_bbb.mp4";

  return (
    <div
      className="glass-card overflow-hidden group relative flex flex-col cursor-pointer transition-all duration-300 hover:border-slate-600 hover:shadow-2xl hover:-translate-y-1 h-[380px]"
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
    >
      <div className="absolute inset-0 z-0 bg-slate-900">
        {isVideoProvider ? (
          <>
            <video
              ref={videoRef}
              src={videoSrc}
              className="w-full h-full object-cover opacity-60 group-hover:opacity-100 transition-opacity duration-500"
              loop
              muted
              playsInline
            />
            <div className="absolute top-4 left-4 z-20">
              <span className="bg-slate-950/80 text-[10px] px-3 py-1.5 rounded-full text-brand-yellow font-bold border border-slate-700/50 backdrop-blur-md uppercase tracking-wider">
                Higsfield
              </span>
            </div>
            <div className="absolute inset-x-0 bottom-0 h-3/4 bg-gradient-to-t from-slate-950 via-slate-950/80 to-transparent"></div>
          </>
        ) : (
          <div className="w-full h-full bg-gradient-to-br from-slate-800 to-slate-900 border-t border-slate-700">
            <div className="absolute inset-x-0 bottom-0 h-1/2 bg-gradient-to-t from-slate-950 via-slate-950/60 to-transparent"></div>
          </div>
        )}
      </div>

      <div className="relative z-10 p-6 flex flex-col h-full justify-end">
        <h3 className="text-2xl font-black text-slate-100 mb-2 uppercase tracking-wide">
          {item.title}
        </h3>
        <p className="text-sm text-slate-400 mb-5 line-clamp-2 leading-relaxed font-medium">
          {item.description}
        </p>
        <div className="flex flex-wrap gap-2 mb-6">
          {item.tags.map((tag) => (
            <span
              key={tag}
              className="text-[10px] uppercase font-bold tracking-wider text-slate-300 bg-slate-800/80 px-2.5 py-1 rounded-md border border-slate-700/50"
            >
              {tag}
            </span>
          ))}
        </div>
        <div className="flex items-center justify-between mt-auto pt-4 border-t border-slate-800/50">
          <button
            className="flex items-center gap-2 text-xs font-bold text-slate-400 hover:text-white transition-colors"
            onClick={(e) => {
              e.stopPropagation();
              navigator.clipboard.writeText(item.examplePrompt || "");
              toast("프롬프트가 복사되었습니다!", "copy");
            }}
          >
